foreach ($s in $screens) {
    $name = $s.Name
    $htmlUrl = $s.HTML
    $imgUrl = $s.Img
    $width = $s.Width
    
    if ($htmlUrl) {
        Write-Output "Downloading HTML for $name..."
        .\scripts\fetch-stitch.ps1 -Url $htmlUrl -OutputPath ".stitch/designs/$name.html"
    }
    
    if ($imgUrl) {
        Write-Output "Downloading Image for $name..."
        $fullImgUrl = "$imgUrl=w$width"
        .\scripts\fetch-stitch.ps1 -Url $fullImgUrl -OutputPath ".stitch/designs/$name.png"
    }
}
